VALUES
  ('real-estate-moex-01014', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲授權乙為代理人，由乙代為與丙協議及締結房屋買賣事宜。下列敘述，何者正確？', '["乙明知該房屋有瑕疵仍與丙締約時，甲得對丙主張瑕疵擔保責任", "乙受甲之授權後，得再另受丙之授權，同時代理甲、丙締結買賣契約", "乙死亡時，代理權消滅，不能為繼承之標的", "乙不得為限制行為能力人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01015', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '乙與甲約定，於甲大學畢業時，乙將贈與甲汽車一輛。此項贈與契約所附約款之性質如何？', '["終期", "始期", "停止條件", "解除條件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01016', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '債權人甲不得代位其債務人乙，行使乙對第三人丙之何項權利？', '["不動產登記請求權", "扶養請求權", "實行抵押權", "提起訴訟之權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01017', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列關於因債務不履行而解除契約之敘述，何者正確？', '["債權人解除契約者，即不得再向債務人請求損害賠償", "因債務人給付不能而為解除時，債權人仍須對債務人為履行之催告始得解除", "如債權人為履行之催告時未定期間，催告後經相當期間，仍得逕為解除", "因解除而互負回復原狀義務時，債務人不得主張同時履行抗辯權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01018', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙締結由甲出售其所有之建物予乙之買賣契約，但該建物實際上已於甲、乙締約前一日因火災而全 部燒毀。該買賣契約效力如何？', '["效力未定", "乙得解除契約", "乙得撤銷契約", "無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01019', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙締結由甲出售10打市面上普遍流通之紅酒予乙之買賣契約，甲依約於約定期日將標的物運送至乙 之住所地時，乙以自己尚未備妥儲藏場所為由拒絕受領。甲不得已乃將物品運回繼續保管，卻於保管期 間中該等紅酒全數破裂。下列敘述，何者正確？', '["即使紅酒之破裂係因甲之重大過失所致，乙亦不得向甲主張損害賠償", "如紅酒之破裂係因不可抗力所致，乙之價金債務消滅", "甲之種類債務尚未特定", "甲之債務成為給付不能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01020', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為成年人，因精神障礙而受監護之宣告，某日甲精神回復而有識別能力，向乙購買手機一只，惟因過 失打破櫃台玻璃。下列敘述，何者正確？', '["甲與乙之手機買賣契約無效，關於打破櫃台玻璃不成立侵權行為", "甲與乙之手機買賣契約有效，關於打破櫃台玻璃成立侵權行為", "甲與乙之手機買賣契約無效，關於打破櫃台玻璃成立侵權行為", "甲與乙之手機買賣契約效力未定，關於打破櫃台玻璃不成立侵權行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01021', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其對乙之債權讓與予丙。下列何者會使此債權讓與無效？', '["甲乙間有不得讓與之特約，但丙為善意之情形", "甲未將證明債權之文件交付予丙", "乙不同意甲丙間之債權移轉行為", "該債權係甲為維持生活所必須之債權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01022', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙、丙三人對丁負有各自分擔比例為三分之一之300萬元連帶債務。下列敘述，何者正確？', '["連帶債務罹於消滅時效後，甲對丁為債務之承認時，該中斷時效之效力及於乙、丙", "甲以時價300萬元之珠寶對丁為代物清償時，如事前未得乙、丙同意，甲不得向乙、丙求償", "甲對丁清償300萬元時，如乙無資力，則甲得對丙求償200萬元", "甲對丁先清償90萬元時，甲得對乙、丙分別求償30萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01023', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲賣A屋給乙，尚未移轉交付，嗣後A屋因可歸責於丙之事由失火滅失，然甲對A屋投有火災保險。下 列敘述，何者錯誤？', '["甲得主張免給付義務，乙亦得主張免對待給付", "此為給付不能，甲、乙間之買賣契約無效", "乙得履行對待給付後，請求甲讓與對失火肇事者丙之損害賠償請求權", "乙得依民法第225條第2項請求甲交付保險金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
